import MainBtns from "./Buttons/MainBtns";

function CourseBuyCard({TextPlaceholder, styles}) {
  return (
    <div className="course-buy-card">
      <div className="course-buy-image"></div>
      <p className="course-buy-text">Этот курс включает в себя:</p>

      <h3 className="course-buy-price">Price</h3>

      <MainBtns Text={"Добавить в корзину"} Style={"purple-btn"}/>
      <MainBtns Text={"Купить сейчас"} Style={"null-btn"}/>
    </div>
  );
}

export default CourseBuyCard;
